// ---- Safe read helpers ----
function safeParse(v) {
  if (!v) return null;
  if (typeof v === 'object') return v;
  if (typeof v === 'string') {
    let s = v.trim();
    // strip code fences like ```json ... ```
    s = s.replace(/^```(?:json)?/i, '').replace(/```$/i, '').trim();
    try { return JSON.parse(s); } catch { return null; }
  }
  return null;
}
const userMsg =
  $json.message ||
  $json.body?.message ||
  $json.query?.message ||
  '';

// AI Agent may return JSON string in output/result or an object at top-level
const raw =
  safeParse($json.output) ||
  safeParse($json.result) ||
  ($json.intent ? $json : {}) ||
  {};

const e = raw.entities || {};
const norm = (v) => (v == null ? '' : (typeof v === 'string' ? v.trim() : v));

// Gas normalization (aliases)
const gasAlias = {
  o2: 'Oxygen', oxygen: 'Oxygen',
  n2: 'Nitrogen', nitrogen: 'Nitrogen',
  h2: 'Hydrogen', hydrogen: 'Hydrogen',
  co2: 'Carbon Dioxide', 'carbon dioxide': 'Carbon Dioxide',
  ar: 'Argon', argon: 'Argon',
  he: 'Helium', helium: 'Helium',
  ch4: 'Methane', methane: 'Methane'
};
const gasRaw = norm(e.gas);
const gasNorm = gasAlias[String(gasRaw).toLowerCase()] || gasRaw;

// Intent with fallbacks
let intent = String(raw.intent || '').toLowerCase() || 'unknown';

// If classifier was unsure, fix common cases via heuristics
if (intent === 'unknown') {
  const t = String(userMsg).toLowerCase().trim();

  // Greeting / small talk
  if (/^(hi|hello|hey|yo|hii+|good (morning|afternoon|evening)|how (are|r) (you|u)|who (are|r) you|thanks?|ok(ay)?)\b/.test(t)) {
    intent = 'greeting';
  }
  // Clear datasheet keywords
  else if (/(msds|sds|tds|data ?sheet|spec(ification)? ?sheet|product ?sheet|safety ?sheet)/i.test(userMsg)) {
    intent = 'datasheet';
  }
}

const duration = Number.isFinite(+e.duration_min) ? +e.duration_min : 0;

// Multi-intent support: extract intents[] array, fallback to [intent]
let intents = [];
if (Array.isArray(raw.intents) && raw.intents.length > 0) {
  intents = raw.intents.map(i => String(i).toLowerCase().trim()).filter(Boolean);
  if (intent !== 'unknown' && !intents.includes(intent)) intents.unshift(intent);
} else if (intent !== 'unknown') {
  intents = [intent];
}
const isMultiIntent = intents.length > 1;

return {
  intent,
  intents,
  isMultiIntent,
  confidence: Number(raw.confidence ?? 0),
  entities: {
    gas: gasNorm,
    sheet_id: norm(e.sheet_id),
    purity: norm(e.purity),
    quantity: norm(e.quantity),
    location: norm(e.location),
    email: norm(e.email),
    phone: norm(e.phone),
    account_no: norm(e.account_no),
    order_no: norm(e.order_no),
    preferred_date: norm(e.preferred_date),
    preferred_time: norm(e.preferred_time),
    duration_min: duration,
    notes: norm(e.notes)
  },
  // convenience for downstream nodes
  message: userMsg
};

