  JSON.stringify(
    (() => {
      const g = $('Delivery Status Agent').first().json || {};
      const raw = g.output ?? g.text ?? g.message ?? g;

      const intentType = $('downstream node').first().json?.intent || 'delivery_update';
      const confidence = $('downstream node').first().json?.confidence ?? null;

      const CLARIFICATION_PHRASES = ['please provide', 'could you please', 'could you provide',
        'please share', 'please let me know', 'kindly provide', 'what is your order',
        'can you provide', 'can you share'];

      const responseText = String(typeof raw === 'string' && raw ? raw : '');

      // Try to parse structured JSON output from the agent
      let parsed = null;
      try {
        parsed = typeof raw === 'string' ? JSON.parse(raw) : (typeof raw === 'object' && raw !== null ? raw : null);
      } catch (_) {
        // Try to extract JSON block from markdown-wrapped output
        try {
          const jsonMatch = responseText.match(/```(?:json)?\s*([\s\S]+?)\s*```/) || responseText.match(/(\{[\s\S]+\})/);
          if (jsonMatch) parsed = JSON.parse(jsonMatch[1]);
        } catch (__) { /* ignore */ }
      }

      if (parsed && (parsed.response_message !== undefined || parsed.data !== undefined)) {
        const msg = String(parsed.response_message || '');
        const lowerMsg = msg.toLowerCase();
        const isClarification = CLARIFICATION_PHRASES.some(p => lowerMsg.includes(p));
        const d = parsed.data || {};

        const delivery_data_raw = {
          order_id:           d.order_id           || null,
          current_status:     d.current_status     || null,
          status_detail:      d.status_detail      || null,
          order_date:         d.order_date         || null,
          promised_ship_date: d.promised_ship_date || null,
          eta:                d.eta                || null,
          delivered_date:     d.delivered_date     || null,
          carrier:            d.carrier            || null,
          tracking_number:    d.tracking_number    || null,
          customer_name:      d.customer_name      || null,
          ship_to_city:       d.ship_to_city       || null,
          country:            d.country            || null,
          received_by:        d.received_by        || null,
          product:            d.product            || null,
        };
        const hasData = !isClarification && Object.values(delivery_data_raw).some(v => v !== null);

        return {
          response_message: msg || 'Delivery status retrieved.',
          sources: isClarification ? [] : [{ doc_id: 'delivery_doc_001', title: 'Delivery Status Document', file_url: '', type: intentType }],
          meta: { confidence },
          ...(hasData ? { delivery_data: delivery_data_raw } : {}),
        };
      }

      // Fallback: agent did not return valid JSON
      const fallbackText = responseText || 'No delivery status available.';
      const lowerFallback = fallbackText.toLowerCase();
      const isFallbackClarification = CLARIFICATION_PHRASES.some(p => lowerFallback.includes(p));

      return {
        response_message: fallbackText,
        sources: isFallbackClarification ? [] : [{ doc_id: 'delivery_doc_001', title: 'Delivery Status Document', file_url: '', type: intentType }],
        meta: { confidence },
      };
    })()
  )
}}

