// Gas alias map: normalized name (from downstream node) → tokens to match in filenames
const GAS_ALIASES = {
  'oxygen':         ['O2','Oxygen'],
  'o2':             ['O2','Oxygen'],
  'nitrogen':       ['N2','Nitrogen'],
  'n2':             ['N2','Nitrogen'],
  'argon':          ['Ar','Argon'],
  'ar':             ['Ar','Argon'],
  'hydrogen':       ['H2','Hydrogen'],
  'h2':             ['H2','Hydrogen'],
  'carbon dioxide': ['CO2'],
  'co2':            ['CO2'],
  'helium':         ['He','Helium'],
  'he':             ['He','Helium'],
  'methane':        ['CH4','Methane'],
  'ch4':            ['CH4','Methane'],
};

function getGasTerms(gasName) {
  if (!gasName) return [];
  const key = gasName.toLowerCase().trim();
  return GAS_ALIASES[key] || [gasName];
}

function fileNameMatchesGas(fileName, gasTerms) {
  if (!gasTerms || gasTerms.length === 0) return true;
  const up = fileName.toUpperCase();
  return gasTerms.some(function(raw) {
    const t = raw.toUpperCase();
    return up.indexOf('_' + t + '_') !== -1
        || up.indexOf('_' + t + '.') !== -1
        || up.indexOf('-' + t + '-') !== -1
        || up.indexOf('-' + t + '.') !== -1
        || up.startsWith(t + '_') || up.startsWith(t + '-')
        || up.endsWith('_' + t)   || up.endsWith('-' + t);
  });
}

// Read gas entity from downstream node (accessible before Pinecone retrieval)
const gasName = $('downstream node').first().json.entities?.gas || '';
const gasTerms = getGasTerms(gasName);

// Extract unique document sources from Datasheet Pinecone chunks
const chunks = $input.all();
const seen = {};
const dsSources = [];

for (const chunk of chunks) {
  const meta = chunk.json?.document?.metadata ?? {};
  const fileName = meta.file_name || '';
  const dedupeKey = fileName || meta.doc_id || meta.source || '';
  if (!dedupeKey) continue;
  // ── Gas filter: skip if filename doesn't match extracted gas ──
  if (gasTerms.length > 0 && !fileNameMatchesGas(fileName, gasTerms)) continue;
  if (!seen[dedupeKey]) {
    seen[dedupeKey] = true;
    const fileUrl =
      meta.file_url ||
      meta.webContentLink ||
      meta.webViewLink ||
      (meta.file_id ? 'https://drive.google.com/uc?id=' + meta.file_id + '&export=download' : '') ||
      (meta.id      ? 'https://drive.google.com/uc?id=' + meta.id      + '&export=download' : '') ||
      '';
    const docId = fileName.replace(/\.(pdf|txt|docx?)$/i, '') || meta.doc_id || fileName || '';
    dsSources.push({ doc_id: docId, title: fileName || docId, file_url: fileUrl, type: 'datasheet' });
  }
  if (dsSources.length >= 2) break;
}

// Pass gas + gasTerms through so Build Multi Response can reuse them
return {
  dsSources: dsSources,
  chunks: 4,
  gas: gasName,
  gasTerms: gasTerms
};

// Retrieve DS sources + gas context from upstream Extract DS Sources node
const dsResult  = $('Extract DS Sources').first().json;
const dsSources = dsResult.dsSources || [];
const gasName   = dsResult.gas || $('downstream node').first().json.entities?.gas || '';
const gasTerms  = dsResult.gasTerms || [];

// ── Gas filename-matching helper ──────────────────────────────────────────
function fileNameMatchesGas(fileName, terms) {
  if (!terms || terms.length === 0) return true;
  const up = fileName.toUpperCase();
  return terms.some(function(raw) {
    const t = raw.toUpperCase();
    return up.indexOf('_' + t + '_') !== -1
        || up.indexOf('_' + t + '.') !== -1
        || up.indexOf('-' + t + '-') !== -1
        || up.indexOf('-' + t + '.') !== -1
        || up.startsWith(t + '_') || up.startsWith(t + '-')
        || up.endsWith('_' + t)   || up.endsWith('-' + t);
  });
}

// ── Extract QT sources from Pinecone chunks ───────────────────────────────
const qtChunksAll = $input.all();
const seenQt = {};
const qtSourcesRaw = [];

for (const chunk of qtChunksAll) {
  const meta = chunk.json?.document?.metadata ?? {};
  const fileName = meta.file_name || '';
  const dedupeKey = fileName || meta.doc_id || meta.source || '';
  if (!dedupeKey) continue;
  if (!seenQt[dedupeKey]) {
    seenQt[dedupeKey] = true;
    const fileUrl =
      meta.file_url ||
      meta.webContentLink ||
      meta.webViewLink ||
      (meta.file_id ? 'https://drive.google.com/uc?id=' + meta.file_id + '&export=download' : '') ||
      (meta.id      ? 'https://drive.google.com/uc?id=' + meta.id      + '&export=download' : '') ||
      '';
    const docId = fileName.replace(/\.(pdf|txt|docx?)$/i, '') || meta.doc_id || fileName || '';
    qtSourcesRaw.push({ doc_id: docId, title: fileName || docId, file_url: fileUrl, type: 'quotation' });
  }
}

// ── Gas filter for QT: keep only files whose name matches the queried gas ──
let qtSources = gasTerms.length > 0
  ? qtSourcesRaw.filter(s => fileNameMatchesGas(s.title, gasTerms))
  : qtSourcesRaw;

// Fallback: if filter eliminated everything but we have raw results, log partial
const qtFilteredOut = gasTerms.length > 0 && qtSourcesRaw.length > 0 && qtSources.length === 0;

// Only take best 1 quotation document
qtSources = qtSources.slice(0, 1);

// ── Intent metadata ───────────────────────────────────────────────────────
const intentsList = $('downstream node').first().json.intents || [];
const confidence  = $('downstream node').first().json.confidence ?? null;

// ── Merge sources ─────────────────────────────────────────────────────────
const allSources = [...dsSources, ...qtSources];

// ── Build response message ────────────────────────────────────────────────
const gasStr = gasName ? ' for ' + gasName : '';
const parts = [];
if (dsSources.length > 0) {
  parts.push('Product data sheet' + (dsSources.length > 1 ? 's' : '') + ': ' + dsSources.map(s => s.title).join(', ') + '.');
} else {
  parts.push('No product data sheet was found for this query.');
}
if (qtSources.length > 0) {
  parts.push('Quotation document: ' + qtSources.map(s => s.title).join(', ') + '.');
} else if (qtFilteredOut) {
  parts.push('Quotation documents were found but none matched ' + (gasName || 'the requested product') + ' specifically.');
} else {
  parts.push('No quotation document was found for this query.');
}

const responseMessage = (allSources.length > 0
  ? 'Here are the requested documents' + gasStr + '. '
  : 'I was unable to find the requested documents' + gasStr + '. ')
  + parts.join(' ');

return {
  result: {
    response_message: responseMessage,
    sources: allSources,
    meta: {
      confidence: confidence,
      sources_used: allSources.length,
      intents: intentsList
    }
  }
};

